+const ATC_OPERATOR_ACTION_CAPACITY: usize = 64;
+const ATC_OPERATOR_STOP_POLL_INTERVAL: Duration = Duration::from_millis(200);
+const ATC_OPERATOR_MIN_TICK_INTERVAL: Duration = Duration::from_millis(250);
